import React from "react";
import "./AirTransportationsDesc.css";
import download from "../../images/airFreight3.jpeg";

function AirTransportationsDesc() {
  return (
    <div className="transDescContainer">
      <div className="descContainer">
        <div className="imgDescContainer">
          <h1>الشحن الجوي</h1>
          <div className="transDesc">
            لشحناتك العاجلة,نقدم في{" "}
            <span className="highlight">HK Istanbul</span> خدمات الشحن الجوي
            السريع والدقيق,عبر شراكتنا مع كبرى شركات الطيران العالمية,من
            الاستلام وحتى التوصيل النهائي,نتكفل بجميع تفاصيل الشحن, بما في ذلك
            التخليص الجمركي في تركيا, الصين, وايطاليا, مع متابعة الشحنة في كل
            مرحلة
            <p>
              <strong>:خدماتنا تشمل</strong>
            </p>
            <ul class="custom-list">
              <li>شحن فوري إلى أهم الوجهات العالمية.</li>
              <li>تغطية دولية واسعة.</li>
              <li>خدمات خاصة للبضائع الطبية أو سريعة التلف.</li>
              <li>تتبع مباشر لشركة الشحن.</li>
              <li>أسعار مدروسة بعناية لتناسب مختلف الميزانيات.</li>
            </ul>
          </div>
        </div>

        <img src={download} alt="" className="transImg" />
      </div>
    </div>
  );
}

export default AirTransportationsDesc;
