import React, { useEffect, useState } from "react";
import "./intro.css";

function Intro() {
  const [showText, setShowText] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => {
      setShowText(false);
    }, 5000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="intro">
      <p
        className={showText ? "introTexth4" : "introTexth4hidden"}
        variant="h4"
      >
        WE CARE FOR YOUR CARGO
      </p>
      <p
        className={showText ? "introTexth3" : "introTexth4hidden"}
        variant="h3"
      >
        YOUR TRUSTED FORWARDING PARTNER
      </p>
    </div>
  );
}

export default Intro;
