import React from "react";
import "./AirTransportationsDesc.css";
import road from "../../images/road-freight2.jpg";

function RoadTransportationsDesc() {
  return (
    <div className="transDescContainer">
      <div className="descContainer">
        <div className="imgDescContainer">
          <h1>الشحن البري</h1>
          <div className="transDesc">
            نقدم في <span className="highlight">HK Istanbul</span> خدمات الشحن
            البري الآمنة والفعالة في تركيا ودول العالم, سواء كانت الشحنة حمولة
            كاملة او جزئية. نضمن لك توصيلا في الوقت المحدد, تتبعا مباشرا, وخدمة
            موثوقة بأسعار منافسة. شبكتنا الواسعة من الشركاءتضمن مرورا سلسا عبر
            الحدود, وعاملا احترافيا مع الشحنات.
            <p>
              <strong>:خدماتنا تشمل</strong>
            </p>
            <ul class="custom-list">
              <li>شحن دولي عبر شبكة موسعة من الشاحنات.</li>
              <li>توصيل من الباب الى الباب للشحنات الخاصة.</li>
              <li>دعم التخليص الجمركي في تركيا وخارج تركيا.</li>
              <li>نقل البضائع الخاصة وذات درجات الحرارة المحددة.</li>
            </ul>
          </div>
        </div>

        <img src={road} alt="" className="transImg" />
      </div>
    </div>
  );
}

export default RoadTransportationsDesc;
