import React from "react";
import "./aboutUs.css";
import PublicOutlinedIcon from "@mui/icons-material/Public";
import LocalShippingOutlinedIcon from "@mui/icons-material/LocalShipping";
import ThumbUpAltOutlinedIcon from "@mui/icons-material/ThumbUpAlt";
import FlightOutlinedIcon from "@mui/icons-material/Flight";

function AboutUs() {
  return (
    <div className="aboutUsGradBg">
      <div className="aboutUsWhiteBg">
        <div className="gradiantCircle"></div>
        <div className="contentStyle">
          <h1 className="aboutUsTitle">ABOUT US</h1>
          <div className="companyDescContainer">
            <div>
              <LocalShippingOutlinedIcon className="aboutUsIcons" />
              شركة رائدة في الوساطة التجارية والخدمات اللوجستية, متخصصة في
              التجارة الدولية, الاستيراد والتصدير, والشحن بمختلف انواعه.
            </div>
            <div>
              <ThumbUpAltOutlinedIcon className="aboutUsIcons" />
              نقوم بدور الوسيط التجاري بين الموردين والعلماء, ونضمن حماية حقوق
              جميع الاطراف من خلال تعاملات شفافة وآمنة.
            </div>
            <div>
              <FlightOutlinedIcon className="aboutUsIcons" />
              نوفر خدمات شحن بري, بحري, جوي, بالاضافة الى التخليص الجمركي, وخطط
              شحن مخصصة حسب نوع البضائع واحتياجات كل عميل. نركز على منتجات عالية
              الطلب مثل الكاجو, القهوة, الأثاث, والمنسوجات.
            </div>
            <div>
              <PublicOutlinedIcon className="aboutUsIcons" />
              نغطي شحن البضائع الى مختلف دول الشرق الأوسط, اوروبا, آسيا,
              أفريقيا, عبر شبكة واسعة من الشركاء الدوليين وسفن الشحن المتطورة,
              مع الالتزام بالسرعة والكفاءة والموثوقية في كل عملية.
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AboutUs;
