import React from "react";
import "./AirTransportationsDesc.css";
import cargo from "../../images/cargo.jpg";

function ProjectCargoDesc() {
  return (
    <div className="transDescContainer">
      <div className="descContainer">
        <div className="imgDescContainer">
          <h1>شحن المشاريع</h1>
          <div className="transDesc">
            نقدم في <span className="highlight">HK Istanbul</span> خدمات شحن
            المشاريع المتخصصة في نقل الشحنات الثقيلة, كبيرة الحجم, أو المعقدة من
            الناحية اللوجيستية, سواء كانت معدات صناعية, مواد بناء ضخمة, او آلات
            لمشاريع البنية التحتية. نوفر لك حلولا متكاملة تشمل التخطيط, النقل,
            والتنسيق مع جميع الجهات المهنية لضمان وصول الشحنة بأمان وفي الوقت
            المحدد.
            <p>
              <strong>:خدماتنا تشمل</strong>
            </p>
            <ul class="custom-list">
              <li>نقل الشحنات الثقيلة والكبيرة والغير قياسية.</li>
              <li>حلول لوجستية من الباب الى الباب.</li>
              <li>تنسيق مع الموانئ والجهات الجمركية الرسمية.</li>
              <li>
                خدمات تغليف صناعي, دافعات خاصة, وتوصيل آمن الى مواقع المشاريع.
              </li>
              <li>حلول فعالة من ناحية التكلفة دون المساس بجودة التنفيذ.</li>
            </ul>
            سواء كانت شحنتك لمرة واحدة او جزءاً من مشروع طويل الأمد, نحرص على
            إدارة العملية بدقة وشفافية تامة, مع خبرة عالية في إدارة المشاريع
            اللوجستية المعقدة.
          </div>
        </div>

        <img src={cargo} alt="" className="transImg" />
      </div>
    </div>
  );
}

export default ProjectCargoDesc;
