import React from "react";
import ocean from "../../images/ocean.png";
import "./AirTransportationsDesc.css";

function SeaTransportationsDesc() {
  return (
    <div className="transDescContainer">
      <div className="descContainer">
        <div className="imgDescContainer">
          <h1>الشحن البحري</h1>
          <div className="transDesc">
            نقدم في <span className="highlight">HK Istanbul</span> حلول شحن مرنة
            واقتصادية تناسب كافة انواع البضائع, سواء كانت شحنتك كاملة او جزئية.
            نحرص على حفظها بعناية من المصدر حتى الوجهة النهائية, مع توفير جميع
            خدمات الدعم اللوجيستي والتخليص الجمركي.
            <p>
              <strong>:خدماتنا تشمل</strong>
            </p>
            <ul class="custom-list">
              <li>خيارات شحن كامل (FCL) او تجميع (LCL) حسب حجم الشحنة.</li>
              <li>جدولة مرنة مع خطوط شحن عالمية موثوقة.</li>
              <li>أفضل اسعار لحجز الحاويات.</li>
              <li>تنسيق احترافي لعمليات التحميل والتخليص في الميناء</li>
              <li>استيراد وتصدير الى جميع الموانئ العالمية.</li>
            </ul>
          </div>
        </div>

        <img src={ocean} alt="" className="transImg" />
      </div>
    </div>
  );
}

export default SeaTransportationsDesc;
